var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"으으...... 마녀가 되는 것보다 침식체 밥이 되는 게 더 빠를 것 같아......","JPN":"うう……魔女になるより、侵食体の餌になるほうが早そう……","ENG":"Oh no... I think I'll end up getting eaten by a C.O. before I even become a witch...","TWN":"呃呃……看來我還沒成為魔女，就可能先成為侵蝕體的飯菜了……"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"INGRID_STREGA_NULL_NULL","text":{"KOREA":"뭘 혼자서 중얼중얼거리는 거야, 견습?","JPN":"何をぶつぶつ呟いてるの、見習い？","ENG":"What are you mumbling about by yourself, newbie?","TWN":"新來的見習生，妳在碎念什麼呢？"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"INGRID_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"INGRID_STREGA_NULL_NULL","text":{"KOREA":"제법 근성 있는 줄 알았는데 벌써 나자빠진 건 아니지?","JPN":"なかなか根性があると思ったけど、もう弱気になったんじゃないよね？","ENG":"I thought you had some grit. You're not giving up already, are you?","TWN":"還以為妳挺有毅力的，不會這麼快就打退堂鼓了吧？"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"INGRID_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"그렇지 않아도 온 몸이 쑤셔 죽겠어......","JPN":"ただでさえ全身がズキズキ痛むのに……","ENG":"Actually, I'm already sore all over...","TWN":"渾身酸痛的要命……"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INGRID_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"넌 괜찮아? 여기 온 뒤로 엄청 열심히 싸우고 다녔잖아?","JPN":"あなたは大丈夫ですか？　ここに来てから、ずっと戦ってますよね？","ENG":"Are you okay? You've been fighting so hard since we got down here.","TWN":"妳還好嗎？來到這裡之後妳就一直沒有停止戰鬥。"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INGRID_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"INGRID_STREGA_NULL_NULL","text":{"KOREA":"당연하지! 이 정도로 약한 소릴 해서는 최강의 마녀가 될 수 없다구!","JPN":"当たり前でしょ！　この程度で弱音を吐いていたら、最強の魔女にはなれないもの！","ENG":"Of course I'm fine! I'll never become the greatest witch if I wimp out now!","TWN":"當然！就這點還難不倒我，不然如何成為最強的魔女呢！"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INGRID_STREGA_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L10_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"최강의 마녀?","JPN":"最強の魔女？","ENG":"The greatest witch?","TWN":"最強的魔女？"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"INGRID_STREGA_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L12_1","type":"dialog","speaker":"INGRID_STREGA_NULL_NULL","text":{"KOREA":"그래. 난 어렸을 때부터 <color=#ffd34c>소녀마녀 네크로노미코</color> 같은 강한 마녀가 되는 게 꿈이었거든.","JPN":"そうよ。私は幼い頃から<color=#ffd34c>魔法少女ネクロノミコ</color>のように強い魔女になることが夢だったの。","ENG":"Yeah. It's always been my dream to become a powerful witch like <color=#ffd34c>Necronomiko the Girl Witch</color>.","TWN":"嗯，我從小的夢想就是成為像<color=#ffd34c>小魔女通靈美子</color>一樣的頂尖魔女。"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INGRID_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"INGRID_STREGA_NULL_NULL","text":{"KOREA":"뭐, 나도 바보는 아니니까 만화가 현실이 아니라는 것 정도는 알고 있어.","JPN":"まあ、私も漫画と現実が違うってことくらいわかってるよ。","ENG":"Of course, I'm not so stupid to think that an anime is reality.","TWN":"不過我沒傻到把漫畫當作現實。"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INGRID_STREGA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"INGRID_STREGA_NULL_NULL","text":{"KOREA":"원래대로라면 그냥 코스프레 정도로 만족하고 끝났겠지.","JPN":"本来なら、ただコスプレをするくらいで満足していたでしょうね。","ENG":"Normally, I'd probably be satisfied with just a little cosplay.","TWN":"如果是以前，我可能就滿足於扮裝了。"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INGRID_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"INGRID_STREGA_NULL_NULL","text":{"KOREA":"하지만 보시라! 나도 이렇게 워치를 얻고 카운터가 됐단 말씀!","JPN":"でもほら！　私はウォッチを手に入れてカウンターになったのよ！","ENG":"But behold! I too have earned a Watch and become a Counter!","TWN":"但現在妳看！我成為了擁有能量環的制裁者！"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INGRID_STREGA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"INGRID_STREGA_NULL_NULL","text":{"KOREA":"이건 나더러 마녀의 길을 걸으라는 하늘의 뜻이 분명하잖아?","JPN":"これは私に魔女の道を歩みなさいという天の啓示でしょ？","ENG":"Surely this is fate's way of telling me to become a witch!","TWN":"這必定是為了讓我成為魔女的天意啊！"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INGRID_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"INGRID_STREGA_NULL_NULL","text":{"KOREA":"그래서 진짜 마녀가 되려면 어떻게 해야 하는지 이것저것 알아보다가 라우라랑 에블린을 알게 됐어.","JPN":"それで本物の魔女になる方法をあれこれ調べるうちに、ラウラとエヴリンのことを知ったの。","ENG":"And so I dug around for how I could become a real witch. That's when I ran into Laura and Evelyn.","TWN":"就在我為了成為真正的魔女而苦惱的時候，遇到了蘿拉和伊芙琳。"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INGRID_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"INGRID_STREGA_NULL_NULL","text":{"KOREA":"다짜고짜 승부를 걸었다가 가게를 박살내 버리는 바람에 첫 인상은 영 꽝이었지만......","JPN":"いきなり勝負を申し込んだ上に店をメチャクチャにしたから、\\n第一印象は最悪だったと思うけど……","ENG":"Although I made a terrible first impression because I challenged them to a duel and pretty much destroyed their cafe...","TWN":"我什麼都不管就先打了一架，結果差點把店給毀了，所以給人家的第一印象不怎麼好……"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INGRID_STREGA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"INGRID_STREGA_NULL_NULL","text":{"KOREA":"어쨌든 지금은 마녀 협회의 일원으로 이렇게 노력하고 있다고!","JPN":"今は魔女協会の一員として努力してるんだから！","ENG":"One way or the other, I ended up becoming a member of the Association! So here I am!","TWN":"但現在我已經成為了魔女協會的一員，並在為此奮鬥！"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INGRID_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"INGRID_STREGA_NULL_NULL","text":{"KOREA":"이번에야말로 제일 좋은 재료들을 모아서 그 두 사람이 깜짝 놀랄 만큼 멋진 코스튬을 만들 거야.","JPN":"今回こそ一番良い材料を集めて、あの二人があっと驚くほど素敵なコスチュームを作るのよ。","ENG":"This time, I'll gather the best materials ever to make a costume that will impress even the two of them.","TWN":"這次我一定要集齊最好的材料，做出讓她們兩個大吃一驚的服裝。"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INGRID_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"INGRID_STREGA_NULL_NULL","text":{"KOREA":"그러면 그 까칠한 라우라도 날 정식 마녀로 인정할 수밖에 없겠지! 후후후!","JPN":"そうしたら、あの厳しいラウラも私を正式な魔女として認めるはず！　ふふふ！","ENG":"I'm sure even that grouchy Laura will have to officially recognize me as a witch then! Heh heh!","TWN":"這樣一來，挑剔的蘿拉也只能認可我是正式魔女了！呼呼呼！"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INGRID_STREGA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"어? 그럼 너도 아직 정식 마녀가 아닌 거야?","JPN":"あれ？　あなたもまだ正式な魔女じゃないんですか？","ENG":"Huh? You mean you're not officially a witch yet?","TWN":"啊？所以妳還不是正式魔女嗎？"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"INGRID_STREGA_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L25_1","type":"dialog","speaker":"INGRID_STREGA_NULL_NULL","text":{"KOREA":"아, 그건 말이지 그러니까...... 하하......","JPN":"あ、それはだから……はは……","ENG":"Oh, about that... It's a long story... Hah hah...","TWN":"啊，這個，就是……哈哈……"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"INGRID_STREGA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L27_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"둘 다 견습 주제에 이런 곳에서 노닥거리고 있다니 여유가 넘치나 보네.","JPN":"二人とも見習いのくせにこんな所で遊んでいるなんて、余裕たっぷりのようだな。","ENG":"You apprentices must think this is some kind of a joke, seeing as you're goofing around in a place like this.","TWN":"妳們兩個菜鳥，居然敢在這裡偷懶。"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"재료 할당량은 다 채우고 노는 거겠지?","JPN":"材料のノルマは達成してるんだろうな？","ENG":"I'm sure you filled your quota already? Of course you wouldn't be slacking off if you haven't.","TWN":"材料都收集好了嗎？"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"죄, 죄송합니다! 지금 바로 일어날게요!","JPN":"す、すみません！　今すぐやります！","ENG":"S-sorry! I'll get up right away!","TWN":"對，對不起！我們馬上就起來！"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INGRID_STREGA_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L32_1","type":"dialog","speaker":"INGRID_STREGA_NULL_NULL","text":{"KOREA":"날 뭘로 보는 거야? 당연히 다 채웠지!","JPN":"私を誰だと思ってるの？　とっくに達成してるよ！","ENG":"Who do you think I am? Of course I filled it!","TWN":"把我當什麼了？當然都收集好了！"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INGRID_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"INGRID_STREGA_NULL_NULL","text":{"KOREA":"그러니까 이번 코스튬 만들 때는 나도 끼워 주는 거 맞지?","JPN":"だから今回のコスチューム作りに私も混ぜてくれるよね？","ENG":"So you'll let me join you when you make the costumes this year, right?","TWN":"所以這次製作服裝的時候也可以讓我參加了吧？"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INGRID_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"무슨 바보 같은 소리야? 뭘 믿고 견습 마녀한테 그런 일을 맡겨?","JPN":"何バカなこと言ってるんだ？　何を信じて見習い魔女に仕事を任せる？","ENG":"Don't be ridiculous! I'll never trust an apprentice with something like that!","TWN":"妳說什麼傻話？製作服裝怎麼可能交給見習魔女來做？"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"INGRID_STREGA_NULL_NULL","text":{"KOREA":"마, 맡겨만 주면 나도 잘할 수 있다고!","JPN":"ま、任せてさえくれれば私にだってできる！","ENG":"B-but you can trust me! I can do a great job!","TWN":"只、只要交給我，我一定能做好！"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INGRID_STREGA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L39_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"그래? 너 바느질은 할 줄 알아?","JPN":"そうか？　裁縫はできるのか？","ENG":"Really? Do you even know how to sew?","TWN":"是嗎？妳會縫紉嗎？"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INGRID_STREGA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L40_1","type":"dialog","speaker":"INGRID_STREGA_NULL_NULL","text":{"KOREA":"바, 바느질? 으으, 그건 별로 자신 없는데......","JPN":"さ、裁縫？　うう、それは自信ないけど……","ENG":"S-sew? Oh... I'm not very confident about that...","TWN":"縫、縫紉？額，我不太會欸……"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INGRID_STREGA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L41_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"흥. 그것 봐.","JPN":"ふん。ほらな。","ENG":"Hmpf. See?","TWN":"哼，我就知道。"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INGRID_STREGA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L42_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"재료 수집에나 집중해. 괜히 오르지도 못할 나무 쳐다보지 말고.","JPN":"材料の収集に集中しろ。無駄な高望みはしないことだな。","ENG":"Just focus on gathering the materials for now. You've still got a long ways to go.","TWN":"好好收集材料吧，別一天到晚做白日夢了。"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INGRID_STREGA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L43_1","type":"dialog","speaker":"INGRID_STREGA_NULL_NULL","text":{"KOREA":"하, 하지만 정식 마녀가 되려면 마법이 담긴 의복 제작 시험을 통과해야 한다면서?","JPN":"で、でも正式な魔女になるには、衣服製作試験を通らないといけないんでしょ？","ENG":"B-but I thought I had to make some magic garb in order to pass the test to officially become a witch!","TWN":"不，不是說要成為正式魔女，就要通過製作蘊含魔法的服裝考試嗎？"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INGRID_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"INGRID_STREGA_NULL_NULL","text":{"KOREA":"그러면 난 올해에도...... 정식 마녀가 될 수 없잖아......","JPN":"じゃあ私は今年も……正式な魔女になれないじゃない……","ENG":"And that means... I can't become a witch this year...","TWN":"這樣一來，我今年……也不能成為正式魔女了……"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INGRID_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INGRID_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"괜찮아! 내가 도와줄게!","JPN":"大丈夫！　私が手伝います！","ENG":"Don't worry! I'll help you!","TWN":"沒關係！我來幫妳！"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"INGRID_STREGA_NULL_NULL","text":{"KOREA":"견습?","JPN":"君が？","ENG":"Apprentice?","TWN":"見習？"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"INGRID_STREGA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L2_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"나, 싸움은 못해도 바느질은 자신 있어! 할머니가 뜨개질할 때 옆에서 배웠거든!","JPN":"私、戦うのは苦手でも裁縫なら自信があるんです！\\nお婆ちゃんが編み物してる時にずっと横で見て習ったので！","ENG":"I might not be much of a fighter, but I sure know how to sew! I learned from my grandma when she was knitting!","TWN":"我雖然不會打架，但縫紉還是會一點的！奶奶做針線活的時候，我有在旁邊學！"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"내가 어떻게 하는지 가르쳐 줄게. 너라면 손도 빠르니까 금방 배울 수 있을 거야.","JPN":"私がやり方を教えます。あなたは手先が器用だからすぐに覚えられると思います。","ENG":"I'll teach you how it's done. I'm sure you'll learn it in no time since you're so good with your hands.","TWN":"我來教妳。妳學的快，肯定馬上就能學會的。"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"INGRID_STREGA_NULL_NULL","text":{"KOREA":"너......! 진짜 좋은 애였구나!","JPN":"君……！　本当にいい子なのね！","ENG":"You... You're awesome!","TWN":"妳……！真是個好人啊！"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"INGRID_STREGA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L7_1","type":"dialog","speaker":"INGRID_STREGA_NULL_NULL","text":{"KOREA":"마음에 들었어! 앞으로 힘쓸 사람 필요할 땐 나한테 말만 해!","JPN":"気に入った！　これから力仕事をする時は私に言ってちょうだい！","ENG":"I think I like you! Let me know if you ever need my brute force with anything!","TWN":"妳很不錯！以後有什麼體力活的話，一定要叫上我！"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"INGRID_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"이봐, 견습 둘이서 뭘 멋대로 정하고 있는 거야?","JPN":"おい、見習い二人で何を勝手に決めてるんだ？","ENG":"Stop deciding things on your own, you two. You're both just apprentices.","TWN":"喂，誰允許妳們兩個見習定規矩的？"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_HATE"}}}},{"id":"L11_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"애초에 정식 마녀 시험은 자기 힘으로 통과해야 의미가 있는 거라고.","JPN":"そもそも正式な魔女になる試験は、自力で通ってこそ意味があるんだ。","ENG":"The witch indoctrination test is only meaningful if you pass it on your own.","TWN":"魔女考試只有憑自己的能力通過才有意義。"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"후훗. 그렇게 딱딱하게 굴 것까진 없잖아, 라우라.","JPN":"ふふっ。そう固いこと言わなくてもいいじゃない、ラウラ。","ENG":"Hah hah, there's no need to be so uptight, Laura.","TWN":"嘿嘿，別這麼死板啊，蘿拉。"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"잉그리드도 여기서 점원 일만 한 지 꽤 오래됐는데 기회를 줘야지.","JPN":"イングリッドも長いこと店員として働いてきたのだから、チャンスをあげないと。","ENG":"Ingrid's been working here for a while. She deserves a chance.","TWN":"英格麗在這裡當店員這麼久了，也該給個機會了。"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"의복 제작 시험의 핵심은 마력 운용 능력을 평가하는 거니까, 바느질이 서툴러도 입을 수만 있다면 그만이고.","JPN":"衣服製作試験は魔力の運用能力を評価するのが目的だから、\\n裁縫が苦手でもとりあえず着られるように仕上がればいいんだし。","ENG":"The costume part of the test is meant to gauge how well you can manage your mana. It'll be fine as long as you can put it on, even if your sewing's wonky.","TWN":"製作服裝的考試，核心在於評價運用魔力的能力，所以即使縫紉技術一般，只要能穿就可以了。"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"끄응......","JPN":"ううっ……","ENG":"Ugh...","TWN":"呃……"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"맘에 안 들지만, 이번 한 번은 넘어가 줄게.","JPN":"不満がなくはないが、今回だけは見逃してやる。","ENG":"It doesn't sit well with me, but I'll let it slide this time.","TWN":"雖然我不是很贊同，但這次我就睜一眼閉一眼吧。"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L17_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"......하여튼 에블린 넌 물러 터졌다니까.","JPN":"……ったく、エヴリンは甘すぎるんだ。","ENG":"You're too soft on her, Evelyn.","TWN":"……伊芙琳妳就是太心軟了。"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"그럼. 난 언제나 어디서나 부드러운 푸딩 같은 여자거든.","JPN":"そうよ。私はいつどこでも柔らかいプリンのような女だから。","ENG":"Of course I am. I'm like a soft, silky pudding.","TWN":"當然，我就是一個如布丁般柔軟的女人。"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"자, 둘 다 들었겠지만 그렇다고 요령 피우면 안 돼.","JPN":"さて、二人とも聞いたと思うけど手を抜いちゃダメよ。","ENG":"Alright, you two. This doesn't mean you can slack off though.","TWN":"好了，妳們倆也聽到了，但不要投機取巧。"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"시험에 쓸 재료를 더 구해야 하니까 지금보다 바쁘게 돌아다녀야 할 거야.","JPN":"試験に使う材料も必要だから、今より忙しく動き回らないとね。","ENG":"We'll need more materials for your tests, so you'd better pick up the pace.","TWN":"還要收集考試的時候用的材料，所以以後會更忙。"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"INGRID_STREGA_NULL_NULL","text":{"KOREA":"좋았어! 두 배든 세 배든 순식간에 해치워 줄게!","JPN":"よし！　二倍でも三倍でもあっという間にやっちゃうから！","ENG":"Great! I'll take them all on, double time!","TWN":"好！不管要多少，我都可以立馬解決！"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"INGRID_STREGA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L24_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"나 뭔가 실수한 것 같은데...... 괜찮겠지?","JPN":"私、何か間違えた気がするけど……大丈夫かな？","ENG":"Why do I feel like I just made a huge mistake? I'll be okay... right?","TWN":"我是不是做錯了什麼……應該沒事吧？"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INGRID_STREGA_NULL_NULL","face":"UNIT_LAUGH"}}}}]`);export{e as default};